     1→//! Query operations for Gallops JSON
     2→//!
     3→//! Implements read operations: muster, saddle, parade, retire.
     4→//! All operations read from Gallops JSON and optionally paddock files.
     5→
     6→use crate::jjrf_favor::Firemark;
     7→use crate::jjrg_gallops::{Gallops, HeatStatus, PaceState};
     8→use serde::Serialize;
     9→use std::fs;
    10→
    11→// ============================================================================
    12→// Muster - List all Heats with summary information
    13→// ============================================================================
    14→
    15→/// Arguments for muster command
    16→#[derive(Debug)]
    17→pub struct MusterArgs {
    18→    pub file: std::path::PathBuf,
    19→    pub status: Option<HeatStatus>,
    20→}
    21→
    22→/// Run the muster command - list Heats as TSV
    23→pub fn run_muster(args: MusterArgs) -> i32 {
    24→    let gallops = match Gallops::load(&args.file) {
    25→        Ok(g) => g,
    26→        Err(e) => {
    27→            eprintln!("jjx_muster: error: {}", e);
    28→            return 1;
    29→        }
    30→    };
    31→
    32→    for (key, heat) in &gallops.heats {
    33→        // Apply status filter if provided
    34→        if let Some(ref filter_status) = args.status {
    35→            if &heat.status != filter_status {
    36→                continue;
    37→            }
    38→        }
    39→
    40→        let pace_count = heat.paces.len();
    41→        let status_str = match heat.status {
    42→            HeatStatus::Current => "current",
    43→            HeatStatus::Retired => "retired",
    44→        };
    45→
    46→        println!("{}\t{}\t{}\t{}", key, heat.silks, status_str, pace_count);
    47→    }
    48→
    49→    0
    50→}
    51→
    52→// ============================================================================
    53→// Saddle - Return context needed to saddle up on a Heat
    54→// ============================================================================
    55→
    56→/// Arguments for saddle command
    57→#[derive(Debug)]
    58→pub struct SaddleArgs {
    59→    pub file: std::path::PathBuf,
    60→    pub firemark: Firemark,
    61→}
    62→
    63→/// Output structure for saddle command
    64→#[derive(Serialize)]
    65→struct SaddleOutput {
    66→    heat_silks: String,
    67→    paddock_file: String,
    68→    paddock_content: String,
    69→    #[serde(skip_serializing_if = "Option::is_none")]
    70→    pace_coronet: Option<String>,
    71→    #[serde(skip_serializing_if = "Option::is_none")]
    72→    pace_silks: Option<String>,
    73→    #[serde(skip_serializing_if = "Option::is_none")]
    74→    pace_state: Option<String>,
    75→    #[serde(skip_serializing_if = "Option::is_none")]
    76→    tack_text: Option<String>,
    77→    #[serde(skip_serializing_if = "Option::is_none")]
    78→    tack_direction: Option<String>,
    79→}
    80→
    81→/// Run the saddle command - return Heat context
    82→pub fn run_saddle(args: SaddleArgs) -> i32 {
    83→    let gallops = match Gallops::load(&args.file) {
    84→        Ok(g) => g,
    85→        Err(e) => {
    86→            eprintln!("jjx_saddle: error: {}", e);
    87→            return 1;
    88→        }
    89→    };
    90→
    91→    let heat_key = args.firemark.display();
    92→    let heat = match gallops.heats.get(&heat_key) {
    93→        Some(h) => h,
    94→        None => {
    95→            eprintln!("jjx_saddle: error: Heat '{}' not found", heat_key);
    96→            return 1;
    97→        }
    98→    };
    99→
   100→    // Read paddock file content
   101→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   102→        Ok(content) => content,
   103→        Err(e) => {
   104→            eprintln!("jjx_saddle: error reading paddock file '{}': {}", heat.paddock_file, e);
   105→            return 1;
   106→        }
   107→    };
   108→
   109→    // Find first actionable pace (rough or primed)
   110→    let mut output = SaddleOutput {
   111→        heat_silks: heat.silks.clone(),
   112→        paddock_file: heat.paddock_file.clone(),
   113→        paddock_content,
   114→        pace_coronet: None,
   115→        pace_silks: None,
   116→        pace_state: None,
   117→        tack_text: None,
   118→        tack_direction: None,
   119→    };
   120→
   121→    for coronet_key in &heat.order {
   122→        if let Some(pace) = heat.paces.get(coronet_key) {
   123→            if let Some(tack) = pace.tacks.first() {
   124→                match tack.state {
   125→                    PaceState::Rough | PaceState::Primed => {
   126→                        output.pace_coronet = Some(coronet_key.clone());
   127→                        output.pace_silks = Some(pace.silks.clone());
   128→                        output.pace_state = Some(match tack.state {
   129→                            PaceState::Rough => "rough".to_string(),
   130→                            PaceState::Primed => "primed".to_string(),
   131→                            _ => unreachable!(),
   132→                        });
   133→                        output.tack_text = Some(tack.text.clone());
   134→                        if tack.state == PaceState::Primed {
   135→                            output.tack_direction = tack.direction.clone();
   136→                        }
   137→                        break;
   138→                    }
   139→                    _ => continue,
   140→                }
   141→            }
   142→        }
   143→    }
   144→
   145→    // Output JSON
   146→    match serde_json::to_string_pretty(&output) {
   147→        Ok(json) => {
   148→            println!("{}", json);
   149→            0
   150→        }
   151→        Err(e) => {
   152→            eprintln!("jjx_saddle: error serializing output: {}", e);
   153→            1
   154→        }
   155→    }
   156→}
