   158→// ============================================================================
   159→// Parade - Display comprehensive Heat status for project review
   160→// ============================================================================
   161→
   162→/// Output format modes for parade command
   163→#[derive(Debug, Clone, Copy, Default, PartialEq, Eq)]
   164→pub enum ParadeFormat {
   165→    /// One line per pace: [state] silks (₢coronet)
   166→    Overview,
   167→    /// Numbered list: N. [state] silks (₢coronet)
   168→    Order,
   169→    /// Full tack text for one pace (requires --pace)
   170→    Detail,
   171→    /// Paddock + all paces with tack text (default)
   172→    #[default]
   173→    Full,
   174→}
   175→
   176→/// Arguments for parade command
   177→#[derive(Debug)]
   178→pub struct ParadeArgs {
   179→    pub file: std::path::PathBuf,
   180→    pub firemark: Firemark,
   181→    pub format: ParadeFormat,
   182→    pub pace: Option<String>,
   183→}
   184→
   185→/// Run the parade command - display comprehensive Heat status
   186→pub fn run_parade(args: ParadeArgs) -> i32 {
   187→    // Validate: detail format requires --pace
   188→    if args.format == ParadeFormat::Detail && args.pace.is_none() {
   189→        eprintln!("jjx_parade: error: --format detail requires --pace <coronet>");
   190→        return 1;
   191→    }
   192→
   193→    let gallops = match Gallops::load(&args.file) {
   194→        Ok(g) => g,
   195→        Err(e) => {
   196→            eprintln!("jjx_parade: error: {}", e);
   197→            return 1;
   198→        }
   199→    };
   200→
   201→    let heat_key = args.firemark.display();
   202→    let heat = match gallops.heats.get(&heat_key) {
   203→        Some(h) => h,
   204→        None => {
   205→            eprintln!("jjx_parade: error: Heat '{}' not found", heat_key);
   206→            return 1;
   207→        }
   208→    };
   209→
   210→    match args.format {
   211→        ParadeFormat::Overview => {
   212→            for coronet_key in &heat.order {
   213→                if let Some(pace) = heat.paces.get(coronet_key) {
   214→                    if let Some(tack) = pace.tacks.first() {
   215→                        let state_str = pace_state_str(&tack.state);
   216→                        println!("[{}] {} ({})", state_str, pace.silks, coronet_key);
   217→                    }
   218→                }
   219→            }
   220→        }
   221→        ParadeFormat::Order => {
   222→            for (idx, coronet_key) in heat.order.iter().enumerate() {
   223→                if let Some(pace) = heat.paces.get(coronet_key) {
   224→                    if let Some(tack) = pace.tacks.first() {
   225→                        let state_str = pace_state_str(&tack.state);
   226→                        println!("{}. [{}] {} ({})", idx + 1, state_str, pace.silks, coronet_key);
   227→                    }
   228→                }
   229→            }
   230→        }
   231→        ParadeFormat::Detail => {
   232→            let target_coronet = args.pace.as_ref().unwrap();
   233→            let pace = match heat.paces.get(target_coronet) {
   234→                Some(p) => p,
   235→                None => {
   236→                    eprintln!("jjx_parade: error: Pace '{}' not found in Heat '{}'", target_coronet, heat_key);
   237→                    return 1;
   238→                }
   239→            };
   240→            if let Some(tack) = pace.tacks.first() {
   241→                let state_str = pace_state_str(&tack.state);
   242→                println!("Pace: {} ({})", pace.silks, target_coronet);
   243→                println!("State: {}", state_str);
   244→                println!("Heat: {}", heat_key);
   245→                println!();
   246→                println!("{}", tack.text);
   247→                if let Some(ref direction) = tack.direction {
   248→                    println!();
   249→                    println!("Direction: {}", direction);
   250→                }
   251→            }
   252→        }
   253→        ParadeFormat::Full => {
   254→            // Read paddock file content
   255→            let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   256→                Ok(content) => content,
   257→                Err(e) => {
   258→                    eprintln!("jjx_parade: error reading paddock file '{}': {}", heat.paddock_file, e);
   259→                    return 1;
   260→                }
   261→            };
   262→
   263→            let status_str = match heat.status {
   264→                HeatStatus::Current => "current",
   265→                HeatStatus::Retired => "retired",
   266→            };
   267→
   268→            println!("Heat: {} ({})", heat.silks, heat_key);
   269→            println!("Status: {}", status_str);
   270→            println!("Created: {}", heat.creation_time);
   271→            println!();
   272→            println!("## Paddock");
   273→            println!();
   274→            println!("{}", paddock_content);
   275→            println!();
   276→            println!("## Paces");
   277→            println!();
   278→
   279→            for coronet_key in &heat.order {
   280→                if let Some(pace) = heat.paces.get(coronet_key) {
   281→                    if let Some(tack) = pace.tacks.first() {
   282→                        let state_str = pace_state_str(&tack.state);
   283→                        println!("### {} ({}) [{}]", pace.silks, coronet_key, state_str);
   284→                        println!();
   285→                        println!("{}", tack.text);
   286→                        if let Some(ref direction) = tack.direction {
   287→                            println!();
   288→                            println!("**Direction:** {}", direction);
   289→                        }
   290→                        println!();
   291→                    }
   292→                }
   293→            }
   294→        }
   295→    }
   296→
   297→    0
   298→}
   299→
   300→/// Helper to convert PaceState to display string
   301→fn pace_state_str(state: &PaceState) -> &'static str {
   302→    match state {
   303→        PaceState::Rough => "rough",
   304→        PaceState::Primed => "primed",
   305→        PaceState::Complete => "complete",
   306→        PaceState::Abandoned => "abandoned",
   307→    }
   308→}
   309→
   310→// ============================================================================
   311→// Retire - Extract complete Heat data for archival trophy
   312→// ============================================================================
   313→
   314→/// Arguments for retire command
   315→#[derive(Debug)]
   316→pub struct RetireArgs {
   317→    pub file: std::path::PathBuf,
   318→    pub firemark: Firemark,
   319→}
   320→
   321→/// Output structure for retire command
   322→#[derive(Serialize)]
   323→struct RetireOutput {
   324→    firemark: String,
   325→    silks: String,
   326→    created: String,
   327→    status: String,
   328→    paddock_file: String,
   329→    paddock_content: String,
   330→    paces: Vec<RetirePace>,
   331→    // TODO: steeplechase array from jjx_rein
   332→    // steeplechase: Vec<SteeplechaseEntry>,
   333→}
   334→
   335→/// Pace structure for retire output (full tack history)
   336→#[derive(Serialize)]
   337→struct RetirePace {
   338→    coronet: String,
   339→    silks: String,
   340→    tacks: Vec<RetireTack>,
   341→}
   342→
   343→/// Tack structure for retire output
   344→#[derive(Serialize)]
   345→struct RetireTack {
   346→    ts: String,
   347→    state: String,
   348→    text: String,
   349→    #[serde(skip_serializing_if = "Option::is_none")]
   350→    direction: Option<String>,
   351→}
   352→
   353→/// Run the retire command - extract complete Heat data for archival
   354→pub fn run_retire(args: RetireArgs) -> i32 {
   355→    let gallops = match Gallops::load(&args.file) {
   356→        Ok(g) => g,
   357→        Err(e) => {
   358→            eprintln!("jjx_retire: error: {}", e);
   359→            return 1;
   360→        }
   361→    };
   362→
   363→    let heat_key = args.firemark.display();
   364→    let heat = match gallops.heats.get(&heat_key) {
   365→        Some(h) => h,
   366→        None => {
   367→            eprintln!("jjx_retire: error: Heat '{}' not found", heat_key);
   368→            return 1;
   369→        }
   370→    };
   371→
   372→    // Read paddock file content
   373→    let paddock_content = match fs::read_to_string(&heat.paddock_file) {
   374→        Ok(content) => content,
   375→        Err(e) => {
   376→            eprintln!("jjx_retire: error reading paddock file '{}': {}", heat.paddock_file, e);
   377→            return 1;
   378→        }
   379→    };
   380→
   381→    // Build paces array with full tack history, ordered per Heat's order array
   382→    let mut paces = Vec::new();
   383→    for coronet_key in &heat.order {
   384→        if let Some(pace) = heat.paces.get(coronet_key) {
   385→            let tacks: Vec<RetireTack> = pace.tacks.iter().map(|tack| {
   386→                RetireTack {
   387→                    ts: tack.ts.clone(),
   388→                    state: match tack.state {
   389→                        PaceState::Rough => "rough".to_string(),
   390→                        PaceState::Primed => "primed".to_string(),
   391→                        PaceState::Complete => "complete".to_string(),
   392→                        PaceState::Abandoned => "abandoned".to_string(),
   393→                    },
   394→                    text: tack.text.clone(),
   395→                    direction: tack.direction.clone(),
   396→                }
   397→            }).collect();
   398→
   399→            paces.push(RetirePace {
   400→                coronet: coronet_key.clone(),
   401→                silks: pace.silks.clone(),
   402→                tacks,
   403→            });
   404→        }
   405→    }
   406→
   407→    let output = RetireOutput {
   408→        firemark: heat_key.clone(),
   409→        silks: heat.silks.clone(),
   410→        created: heat.creation_time.clone(),
   411→        status: match heat.status {
   412→            HeatStatus::Current => "current".to_string(),
   413→            HeatStatus::Retired => "retired".to_string(),
   414→        },
   415→        paddock_file: heat.paddock_file.clone(),
   416→        paddock_content,
   417→        paces,
   418→        // TODO: Call jjx_rein internally to get steeplechase entries
   419→    };
   420→
   421→    // Output JSON
   422→    match serde_json::to_string_pretty(&output) {
   423→        Ok(json) => {
   424→            println!("{}", json);
   425→            0
   426→        }
   427→        Err(e) => {
   428→            eprintln!("jjx_retire: error serializing output: {}", e);
   429→            1
   430→        }
   431→    }
   432→}
