   567→    #[test]
   568→    fn test_retire_output_structure() {
   569→        let output = RetireOutput {
   570→            firemark: "₣AB".to_string(),
   571→            silks: "my-heat".to_string(),
   572→            created: "260101".to_string(),
   573→            status: "current".to_string(),
   574→            paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
   575→            paddock_content: "# Archive this".to_string(),
