        let output = SaddleOutput {
            heat_silks: "my-heat".to_string(),
            paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
            paddock_content: "# Test content".to_string(),
            pace_coronet: Some("₢ABAAA".to_string()),
            pace_silks: Some("my-pace".to_string()),
