        let output = SaddleOutput {
            heat_silks: "my-heat".to_string(),
            paddock_file: ".claude/jjm/jjp_AB.md".to_string(),
            paddock_content: "# All done".to_string(),
            pace_coronet: None,
            pace_silks: None,
