                        PaceState::Rough | PaceState::Primed => {
                            found_coronet = Some(coronet_key.clone());
                            break;
                        }
                        _ => continue,
                    }
                }
            }
        }

        assert_eq!(found_coronet, Some("₢ABAAA".to_string()));
    }
}

